import sympy
def generate_boundary_primes(limit):
    boundary_primes = []
    p = 2
    while len(boundary_primes) < limit:
        next_p = sympy.nextprime(p)
        gap = next_p - p
        scale = p.bit_length() - 1 # A000523
        if gap == scale:
            boundary_primes.append(p)
        p = next_p
    return boundary_primes
print(generate_boundary_primes(50))

